// The received message is stored in 'msg'
// It will have at least a 'payload' property:
//   console.log(msg.payload);
// The 'context' object is available to store state
// between invocations of the function
//   context = {};

msg.user = msg.req.body["user"];
msg.pwd = msg.req.body["pwd"];
msg.tz = msg.req.body["tz"];

return msg;

// the app credentials as supplied by SunSprite
var appname = "kid_Ve5xRCs7Mm";
var appkey  = "a7f19fa982f4448e84b9ab29bd105a8b";

var applogin = new Buffer(appname+":"+appkey).toString('base64'); // b64 formatted login string

var newMsg = {
  url: "http://baas.kinvey.com/user/"+appname+"/login", // REST endpoint for login

  // define header with app-specific login and specify user name and password of SunSprite user
  headers: { 'Content-Type' : 'application/json', 'Authorization' : 'Basic '+applogin },
  payload: JSON.stringify({"username": msg.user, "password": msg.pwd}),

  method: "POST", // POST this request
  res: msg.res,  // carry on the response object
  user: msg.user // and user
}
return newMsg;

var parameters = JSON.parse(msg.payload);

msg.token    = parameters["_kmd"]["authtoken"];
msg.sprite   = parameters["sunSpriteUUID"];
msg.batt     = parameters["lastBatteryPercent"]*100;
msg.luxgoal  = parameters["luxGoal"];
msg.lastsync = parameters["syncRefDate"];
msg.offset   = parameters["timezoneOffsetSec"]/60/60;
msg.metric   = "";
msg.topic    = "meta";

return msg;

var appname = "kid_Ve5xRCs7Mm";

Date.prototype.minusDays = function(days) {
  var dat = new Date(this.valueOf())
  dat.setDate(dat.getDate() - days);
  return dat;
}

Date.prototype.addDays = function(days) {
  var dat = new Date(this.valueOf())
  dat.setDate(dat.getDate() + days);
  return dat;
}

var backthen = new Date().minusDays(365).toISOString().substring(0,10);
var tomorrow = new Date().addDays(1).toISOString().substring(0,10);

// a query for just today where isgoodLux=true, and we want goodLux and date
msg.url = "http://baas.kinvey.com/appdata/"+appname+
'/dailyRecords/?query={"date":{"$lt":"'+tomorrow+'","$gte":"'+backthen+'"}}&fields=accumulatedLux,date';

msg.method = "GET";

// use the AUTHTOKEN obtained in the login flow
msg.headers = { 'Authorization' : 'Kinvey '+msg.token };

return msg;

var payload = "";
var qualityRegex = /\"date\"\:\"(.{10})T(.{12})Z\",\"accumulatedLux\"\:(\d+(.\d+)?)/mg;
  while (matches = qualityRegex.exec(msg.payload)) {
    var myA = matches[1].split("-");
      if (matches[3] > 2*msg.luxgoal) {
        matches[3] = 2*msg.luxgoal;
      }
    var val = (-100+(matches[3]/msg.luxgoal)*100).toFixed(1)
    payload += "[ new Date("+myA[0]+", "+(parseInt(myA[1])-1)+", "+myA[2]+"), "+val+" ],";
  }

msg.topic = "measurement";
msg.payload = payload.slice(0,-1);
return msg;

if (msg.topic != "measurement" && msg.topic != "meta") {
  context.msg = msg;
}

if (msg.topic == "meta") {
  context.user = msg.user;
  context.lastsync = msg.lastsync;
  context.offset = msg.offset;
  context.batt = msg.batt;
  context.luxgoal = msg.luxgoal;
}

if (msg.topic == "measurement") {
  var keyMsg;
  keyMsg = context.msg;
  keyMsg.user = context.user;
  keyMsg.batt = context.batt;
  keyMsg.lastsync = context.lastsync;
  keyMsg.offset = context.offset;
  keyMsg.metric = msg.payload;

  context.msg = undefined;
  context.user = "";
  context.batt = 0;
  context.lastsync = "";
  context.offset = 0;
  context.count = 0;
  context.str = "";
  return keyMsg;
}
